const detail='\n<div>\n    <template v-for="kind in kinds">\n        <template v-if="kind.category == category">\n            <template v-for="work in kind.works">\n                <template v-if="work.name == name">\n                    <div class="container d-none d-sm-block">\n                        <div class="detail-header">\n                            <div class="row">\n                                <div class="col-lg-12">\n                                    <div class="detail-header-bg">{{ work.title_en }}</div>\n                                </div>\n                                <div class="col-lg-10 offset-lg-2">\n                                    <div class="detail-header-content">\n                                        <h1 class="header-content-title">{{ work.title }}</h1>\n                                        <div class="header-content-des">{{ work.description }}</div>\n                                    </div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                \n                    <div class="container">\n                        <div class="detail-body">\n                            <div class="row">\n                                <div class="col-lg-8 col-sm-12">\n                                    <div class="detail-acticle">\n                                        <div class="post-wrap" v-html="post"></div>\n                                    </div>\n                                </div>\n                                <div class="col-lg-4 col-sm-12 order-first order-sm-0">\n                                    <div class="detail-sidebar d-flex flex-column">    \n                                        <div class="detail-sidebar-image order-0 order-sm-0">\n                                            <picture>\n                                                <source v-bind:srcset="work.webp" type="image/webp">\n                                                <img v-bind:src="work.image" v-bind:alt="work.title" />\n                                            </picture>\n                                        </div>\n                                        <div class="detail-sidebar-year order-1 order-sm-1">{{ work.year }}</div>\n                                        <div class="detail-sidebar-title order-2 order-sm-2">{{work.title}}</div>\n                                        <div class="detail-sidebar-link order-3 order-sm-3">\n                                            <a v-if="work.link" class="link-icon icon-website" target="_blank" v-bind:href="work.link">{{work.link}}</a>\n                                            <a v-if="work.github" class="link-icon icon-github" target="_blank" v-bind:href="work.github">{{work.github}}</a>\n                                        </div>\n                                        <hr class="order-5 order-sm-4" />\n                                        <div class="detail-sidebar-subtitle order-6 order-sm-5">負責部分</div>\n                                        <div class="detail-sidebar-des order-7 order-sm-6">\n                                            <ul class="des-list">\n                                            <template v-for="info_content in work.info_contents">\n                                                <li class="des-list-item">{{info_content}}</li>\n                                            </template>\n                                            </ul>\n                                        </div>\n                                        <div class="detail-sidebar-subtitle d-none d-sm-block order-sm-7">工具</div>\n                                        <ul class="tag-list detail-sidebar-tags-wrap order-4 order-sm-8">\n                                            <li class="tag-item" v-for="tag in work.tags">{{tag}}</li>\n                                        </ul>\n                                    </div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </template>\n            </template>\n        </template>\n    </template>\n</div>\n',Detail={props:["category","name"],template:detail,data:()=>({kinds:[],post:"",isMac:!1}),created(){this.fetchData(),this.fetchDataHTML(),this.isMac=navigator.platform.toUpperCase().indexOf("MAC")>=0},mounted:function(){$("#js-goback-btn").addClass("show")},updated(){let t=$(".dev-outter-wrap");!this.isMac&&t.length>0&&t.addClass("hide-scroll")},methods:{fetchData(){fetch("dist/assets/data/works.json").then((t=>t.json())).then((t=>{this.kinds=t}))},fetchDataHTML(){fetch(`dist/assets/data/contents/${this.$route.params.name}.html`).then((t=>t.text())).then((t=>this.post=t)).then((function(){$(".tab-nav").on("click",(function(){let t=$(this).parent(".tab-nav-wrap").attr("data-panel"),e=$(this).attr("data-tabs");$(this).siblings(".active").removeClass("active"),$(this).addClass("active");let i=$(".tab-content-wrap").filter(`[data-panel="${t}"]`);i.find(".active").removeClass("active"),i.find(`[data-tabs="${e}"]`).addClass("active")}))}))},checkRoute:function(){let t=!0;for(let e=0;e<this.kinds.length;e++)if(this.kinds[e].category==this.$route.params.category)for(let i=0;i<this.kinds[e].works.length;i++)this.kinds[e].works[i].name==this.$route.params.name&&(t=!1);t&&this.$router.push("/404-not-found")}},watch:{$route:function(t,e){this.checkRoute()}}};export default Detail;